(function () {
  function addStyle() { if (document.getElementById('vie-style')) return; var s = document.createElement('style'); s.id = 'vie-style'; s.textContent = '.vie-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.vie-checks{display:flex;gap:14px;flex-wrap:wrap}.vie-venn{height:240px;background:#f8fafc;border:1px solid #e5e7eb;border-radius:12px;position:relative;margin:12px 0}.vie-c{position:absolute;width:145px;height:145px;border-radius:50%;border:3px solid;opacity:.48}.vie-a{left:23%;top:24px;background:#e8f4fd;border-color:#007bff}.vie-b{left:39%;top:24px;background:#d4edda;border-color:#28a745}.vie-cs{left:31%;top:72px;background:#fff3cd;border-color:#ffc107}.vie-dot{position:absolute;width:18px;height:18px;border-radius:50%;background:#dc3545;box-shadow:0 0 0 5px rgba(220,53,69,.18);transition:.25s}.vie-out{padding:12px;border-radius:8px;background:#e8f4fd;border-left:4px solid #007bff}'; document.head.appendChild(s); }
  function mount(host){ if(!host||host.dataset.vieMounted)return; host.dataset.vieMounted='1'; addStyle(); host.innerHTML='<div class="vie-wrap"><h4>🧮 Bao hàm - loại trừ cho một phần tử</h4><div class="vie-checks"><label><input data-s="A" type="checkbox" checked> Thuộc A</label><label><input data-s="B" type="checkbox" checked> Thuộc B</label><label><input data-s="C" type="checkbox"> Thuộc C</label></div><div class="vie-venn"><div class="vie-c vie-a">A</div><div class="vie-c vie-b">B</div><div class="vie-c vie-cs">C</div><div class="vie-dot"></div></div><div class="vie-out"></div></div>'; var dot=host.querySelector('.vie-dot'),out=host.querySelector('.vie-out'); function paint(){var A=host.querySelector('[data-s=A]').checked,B=host.querySelector('[data-s=B]').checked,C=host.querySelector('[data-s=C]').checked,r=[A,B,C].filter(Boolean).length,minus=(A&&B)+(A&&C)+(B&&C),plus=A&&B&&C?1:0,net=r-minus+plus; dot.style.left=(A&&B&&C?'47':A&&B?'45':A&&C?'39':B&&C?'52':A?'33':B?'58':C?'47':'10')+'%'; dot.style.top=(A&&B&&C?'50':A&&B?'34':A&&C?'58':B&&C?'58':A?'34':B?'34':C?'72':'82')+'%'; out.innerHTML='Phần tử này được đếm <strong>'+r+'</strong> lần trong |A|+|B|+|C|, bị trừ <strong>'+minus+'</strong> lần, cộng lại <strong>'+plus+'</strong> lần → net = <strong>'+net+'</strong>.';} host.querySelectorAll('input').forEach(function(e){e.addEventListener('change',paint);}); paint(); }
  document.addEventListener('DOMContentLoaded', function(){ document.querySelectorAll('[data-demo="venn-ie-three-sets"]').forEach(mount); });
}());
